package com.example.feature_online

import com.google.gson.Gson
import java.io.BufferedReader
import java.io.BufferedWriter
import java.io.IOException
import java.io.InputStreamReader
import java.io.OutputStreamWriter
import java.io.PrintWriter
import java.net.ServerSocket
import java.net.Socket
import kotlin.jvm.java
import com.example.feature_online.OnlineClientData
import com.example.feature_online.OnlineServerData

enum class GameState {
  WaiTING,
  PLAYING,
  OVER
}

class OnlineGameServer(val port: Int = 50001) {
  private var onlineState: Boolean = false // 是否可以开始联机游戏(2个玩家)
  private var onlinePlayerCount: Int = 0
  private var gameState: GameState = GameState.WaiTING
  private var score: Int = 0

  init {
    try {
      val serverSocket = ServerSocket(port)
      while (true) {
        if (onlinePlayerCount < 2) {
          println("waiting client connect")
          val socket = serverSocket.accept()
          println("accept client connect $socket")
          Thread(OnlineService(socket)).start()
          onlinePlayerCount++
        } else {
          gameState = GameState.PLAYING
          println("online player count is 2. Ready to start game")
        }
      }
    } catch (ex: Exception) {
      ex.printStackTrace()
    }
  }

  inner class OnlineService(private val socket: Socket) : Runnable {
    private var infoReceiver: BufferedReader? = null
    private var infoBroadcaster: PrintWriter? = null

    init {
      try {
        infoReceiver = BufferedReader(InputStreamReader(socket.getInputStream()))
        infoBroadcaster = PrintWriter(BufferedWriter(OutputStreamWriter(socket.getOutputStream(), "utf-8")), true)
      } catch (ex: IOException) {
        ex.printStackTrace()
      }
    }

    override fun run() {
      try {
        while (gameState == GameState.WaiTING) { }
        while (gameState == GameState.PLAYING) {
          val content = infoReceiver!!.readLine()
          var clientData: OnlineClientData = Gson().fromJson(content, OnlineClientData::class.java)
          synchronized() {
            score += clientData.getScore
          }
        }
      } catch (ex: Exception) {
        ex.printStackTrace()
      }
    }

    private fun sendMessage(socket: Socket, message: String) {
      println("messge to client: $message")
      infoBroadcaster!!.println(message)
    }
  }
}

package edu.hitsz.aircraftwar

import android.os.Bundle
import android.util.Log
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import android.view.Window
import android.view.WindowManager
import android.widget.FrameLayout
import edu.hitsz.aircraftwar.Views.GameView
import edu.hitsz.aircraftwar.logic.utils.ImageManager

/**
 * Android 程序入口 - 替代 Swing 的 Main 类
 * @author hitsz
 */
class MainActivity : AppCompatActivity() {

  companion object {
    // 保持与原项目一致的逻辑尺寸（用于游戏坐标计算）
    const val TAG = "MainActivity"
  }

  private lateinit var gameView: GameView

  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)

    window.addFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON)
    setContentView(R.layout.activity_main)

    // 初始化图片管理器
    ImageManager.init(AircraftWarApplication.context)

    // 初始化自定义游戏 View
    gameView = GameView(AircraftWarApplication.context)
    val container = findViewById<FrameLayout>(R.id.game_container)
    container.addView(gameView)

    // 定义游戏结束回调
    gameView.onGameOver = { score ->
      Log.d(TAG, "Game over, score: $score")
    }
  }

  override fun onResume() {
    super.onResume()
    // 恢复游戏循环（对应原 game.action()）
    gameView.startGame()
  }

  override fun onPause() {
    super.onPause()
    // 暂停游戏，避免后台耗电
    gameView.overGame()
  }

  override fun onDestroy() {
    super.onDestroy()
    // 彻底释放资源
    gameView.release()
  }
}

